// Recalculer scores et identifier les priorités
const targets = $input.all().map(item => item.json);
const now = new Date();
const deadline = new Date('2026-10-21');
const daysLeft = Math.ceil((deadline - now) / (1000 * 60 * 60 * 24));

const updates = targets.map(t => {
  // Pénaliser l'inactivité
  const daysSinceContact = t.last_contact_date 
    ? Math.ceil((now - new Date(t.last_contact_date)) / (1000 * 60 * 60 * 24)) 
    : 999;

  let newScore = parseInt(t.score || 0);

  // Urgence temporelle
  if (daysLeft < 60) newScore += 10;
  if (daysLeft < 30) newScore += 20;

  // Pénalité inactivité
  if (daysSinceContact > 30) newScore -= 15;
  if (daysSinceContact > 60) newScore -= 25;

  // Bonus stade avancé
  const stageBonus = { identified: 0, researching: 5, ready: 10, contacted: 15, replied: 25, meeting: 35, proposal: 45, negotiating: 55 };
  newScore += stageBonus[t.status] || 0;

  newScore = Math.max(0, Math.min(100, newScore));

  return { 
    id: t.id, 
    company_name: t.company_name,
    old_score: t.score,
    new_score: newScore,
    days_inactive: daysSinceContact,
    action_needed: daysSinceContact > 14 ? 'follow_up' : 'monitor'
  };
});

return updates.map(u => ({ json: u }));
